      import sailpoint.object.Identity;
      import sailpoint.tools.GeneralException;
      import java.util.List;

      // ── Configuration ──────────────────────────────────────
      String workgroupName = (String) taskResult.getAttribute("workgroupName");
      String tempPassword  = (String) taskResult.getAttribute("tempPassword");
      // ───────────────────────────────────────────────────────

      if (workgroupName == null || workgroupName.trim().equals("")) {
          taskResult.addMessage("ERROR: workgroupName argument is required.");
          return;
      }
      if (tempPassword == null || tempPassword.trim().equals("")) {
          taskResult.addMessage("ERROR: tempPassword argument is required.");
          return;
      }

      // 1. Fetch workgroup
      Identity workgroup = context.getObjectByName(Identity.class, workgroupName);
      if (workgroup == null) {
          taskResult.addMessage("ERROR: Workgroup not found: " + workgroupName);
          return;
      }
      if (!workgroup.isWorkgroup()) {
          taskResult.addMessage("ERROR: '" + workgroupName + "' is not a workgroup.");
          return;
      }

      // 2. Get members
      List members = workgroup.getMembers();
      if (members == null || members.isEmpty()) {
          taskResult.addMessage("WARNING: No members found in workgroup: " + workgroupName);
          return;
      }

      int successCount = 0;
      int errorCount   = 0;

      // 3. Loop and reset
      for (Object obj : members) {
          Identity member = (Identity) obj;
          String memberId   = member.getId();
          String memberName = member.getName();
          try {
              // Re-fetch for full Hibernate-attached object
              member = context.getObjectById(Identity.class, memberId);

              // Set password (IIQ handles salting/hashing internally)
              context.setPassword(member, tempPassword);

              // Force change at next logon
              member.setAttribute("mustResetPassword", true);

              // Persist
              context.saveObject(member);
              context.commitTransaction();

              taskResult.addMessage("OK: Reset password for [" + memberName + "]");
              successCount++;

          } catch (Exception e) {
              taskResult.addMessage("ERROR: Failed for [" + memberName + "]: " + e.getMessage());
              errorCount++;
              // Decache to keep Hibernate session clean after error
              context.decache(member);
          }
      }

      // 4. Summary
      taskResult.addMessage("────────────────────────────────────────");
      taskResult.addMessage("SUMMARY: " + successCount + " succeeded, " + errorCount + " failed.");
